import{_ as r,o as a,c as t,a2 as s}from"./chunks/framework.BWuWLRhz.js";const u=JSON.parse('{"title":"Metrics","description":"","frontmatter":{},"headers":[],"relativePath":"app/metrics.md","filePath":"app/metrics.md"}'),n={name:"app/metrics.md"};function i(o,e,l,p,c,d){return a(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="metrics" tabindex="-1">Metrics <a class="header-anchor" href="#metrics" aria-label="Permalink to &quot;Metrics&quot;">​</a></h1><p>Tragwerk surfaces metrics at two scopes: <strong>server metrics</strong> for the VPS as a whole, and <strong>environment/app metrics</strong> for a specific deployed application. Both offer a live view and historical graphs.</p><h2 id="server-metrics" tabindex="-1">Server metrics <a class="header-anchor" href="#server-metrics" aria-label="Permalink to &quot;Server metrics&quot;">​</a></h2><p>Server metrics cover the health of the VPS itself:</p><ul><li><strong>CPU</strong> usage</li><li><strong>Memory</strong> usage</li><li><strong>Disk</strong> usage</li></ul><p>Tragwerk samples each server over SSH in the background and stores the readings, so live values and historical graphs populate automatically — no setup required on your part.</p><h2 id="environment-app-metrics" tabindex="-1">Environment / app metrics <a class="header-anchor" href="#environment-app-metrics" aria-label="Permalink to &quot;Environment / app metrics&quot;">​</a></h2><p>Application metrics describe the running app within an <a href="/app/environments">environment</a> — aggregated FrankenPHP and Caddy figures summed across the app&#39;s containers:</p><ul><li><strong>Worker pool</strong> — total / busy / ready workers and queue depth</li><li><strong>Threads</strong> — total and busy</li><li><strong>Requests</strong> — total served, plus 4xx and 5xx counts</li><li><strong>Latency</strong> — average request duration (derived from sample deltas)</li><li><strong>In-flight</strong> — requests currently being processed</li></ul><p>Gauges (workers, threads, in-flight) are point-in-time values; counters (requests, durations) are cumulative since container start, so rates and average latency are derived from the difference between consecutive samples.</p><p>The <strong>worker pool</strong> figures are most meaningful for apps running in <a href="/config/applications#workermode">worker mode</a>. Apps in the default classic mode (the PHP-FPM drop-in) still report request, latency, and thread metrics.</p><h2 id="live-updates-and-graphs" tabindex="-1">Live updates and graphs <a class="header-anchor" href="#live-updates-and-graphs" aria-label="Permalink to &quot;Live updates and graphs&quot;">​</a></h2><ul><li><strong>Live tiles</strong> update in real time via <strong>Mercure</strong> (server-sent events). The page subscribes to a live endpoint and re-renders tiles as new samples arrive.</li><li><strong>Historical graphs</strong> are drawn with <strong>uPlot</strong> from data fetched on a data endpoint, letting you inspect trends over time.</li></ul><h2 id="example" tabindex="-1">Example <a class="header-anchor" href="#example" aria-label="Permalink to &quot;Example&quot;">​</a></h2><p>Open <strong>Metrics</strong>, pick the active project and environment, and watch the live worker and request tiles update while the graphs fill in history.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/app/environments">Environments</a></li><li><a href="/app/logs-containers">Logs &amp; Containers</a></li><li><a href="/self-hosting/architecture-on-host">Architecture on the host</a></li></ul>',17)])])}const m=r(n,[["render",i]]);export{u as __pageData,m as default};
